(function(global){
  function escapeHtml(value){
    return String(value)
      .replaceAll("&","&amp;")
      .replaceAll("<","&lt;")
      .replaceAll(">","&gt;")
      .replaceAll('"',"&quot;")
      .replaceAll("'","&#39;");
  }

  function inline(text){
    let value=escapeHtml(text);
    value=value.replace(/`([^`\n]+)`/g,"<code>$1</code>");
    value=value.replace(/\*\*([^*]+)\*\*/g,"<strong>$1</strong>");
    value=value.replace(/\*([^*\n]+)\*/g,"<em>$1</em>");
    value=value.replace(/\[([^\]]+)\]\(([^)]+)\)/g,'<a href="$2">$1</a>');
    return value;
  }

  function divider(line){
    const stripped=String(line||"").trim();
    if(!stripped.includes("|")){
      return false;
    }
    const cells=stripped.replace(/^\||\|$/g,"").split("|").map((cell)=>cell.trim());
    return cells.length>=2 && cells.every((cell)=>/^:?-{3,}:?$/.test(cell));
  }

  function tableRow(line){
    const stripped=String(line||"").trim();
    return Boolean(stripped) && stripped.includes("|") && !divider(stripped);
  }

  function consumeTable(lines,start){
    if(start+1>=lines.length || !tableRow(lines[start]) || !divider(lines[start+1])){
      return null;
    }
    const rows=[lines[start],lines[start+1]];
    let index=start+2;
    while(index<lines.length && tableRow(lines[index])){
      rows.push(lines[index]);
      index+=1;
    }
    return {rows,index};
  }

  function cells(line){
    return String(line||"")
      .trim()
      .replace(/^\||\|$/g,"")
      .split("|")
      .map((cell)=>inline(cell.trim()));
  }

  function renderTable(rows){
    const headerCells=cells(rows[0]);
    const bodyRows=rows.slice(2);
    const thead="<thead><tr>"+headerCells.map((cell)=>"<th>"+cell+"</th>").join("")+"</tr></thead>";
    const tbody=bodyRows.length
      ? "<tbody>"+bodyRows.map((row)=>"<tr>"+cells(row).map((cell)=>"<td>"+cell+"</td>").join("")+"</tr>").join("")+"</tbody>"
      : "";
    return "<table>"+thead+tbody+"</table>";
  }

  function renderParagraph(lines){
    const text=lines.join(" ").trim();
    if(!text){
      return "";
    }
    return "<p>"+inline(text)+"</p>";
  }

  function parse(markdown){
    const source=String(markdown||"").replace(/\r\n/g,"\n");
    const lines=source.split("\n");
    const html=[];
    let paragraph=[];
    let listItems=[];

    function flushParagraph(){
      if(paragraph.length){
        html.push(renderParagraph(paragraph));
        paragraph=[];
      }
    }

    function flushList(){
      if(listItems.length){
        html.push("<ul>"+listItems.map((item)=>"<li>"+inline(item)+"</li>").join("")+"</ul>");
        listItems=[];
      }
    }

    for(let index=0;index<lines.length;index+=1){
      const rawLine=lines[index];
      const line=rawLine.trim();

      const table=consumeTable(lines,index);
      if(table){
        flushParagraph();
        flushList();
        html.push(renderTable(table.rows));
        index=table.index-1;
        continue;
      }

      if(!line){
        flushParagraph();
        flushList();
        continue;
      }

      const heading=line.match(/^(#{1,6})\s+(.*)$/);
      if(heading){
        flushParagraph();
        flushList();
        const level=heading[1].length;
        html.push("<h"+level+">"+inline(heading[2])+"</h"+level+">");
        continue;
      }

      const quote=line.match(/^>\s?(.*)$/);
      if(quote){
        flushParagraph();
        flushList();
        html.push("<blockquote><p>"+inline(quote[1])+"</p></blockquote>");
        continue;
      }

      const unordered=line.match(/^[-*]\s+(.*)$/);
      if(unordered){
        flushParagraph();
        listItems.push(unordered[1]);
        continue;
      }

      flushList();
      paragraph.push(rawLine);
    }

    flushParagraph();
    flushList();
    return html.join("");
  }

  global.marked={parse:parse};
})(window);
